const response = $input.first().json;
const values = response.values || [];
if (values.length < 2) return [];
const headers = values[0];
const rows = values.slice(1);
return rows
  .filter(row => row && row.some(cell => cell && String(cell).trim() !== ''))
  .map(row => ({
    json: Object.fromEntries(headers.map((h, i) => [h, row[i] !== undefined ? row[i] : '']))
  }));

// n8n Code Node - Buscar Slack ID para TODOS los items
// Modo recomendado del Code node:
// - Mode: Run Once for All Items
// - Language: JavaScript
//
// Requisitos Slack Bot Token scopes:
// - users:read
// - users:read.email
//
// Importante:
// - En tu input el campo de email puede llegar como "Email" o " Email".
// - Este código conserva Alias en TODOS los outputs.
// - Corrige el bug donde Alias se perdía en los matches exitosos por email.
// - Ignora filas completamente vacías para no generar muchos _skip no_match_found.
//
// Seguridad:
// Reemplaza el valor de SLACK_TOKEN por tu token real o usa una variable segura de n8n.

const SLACK_TOKEN = $env.SLACK_BOT_TOKEN;

// Ajusta este delay si Slack te da rate limit.
// 0 = sin pausa.
// 250 = pausa suave entre llamadas lookupByEmail.
const DELAY_MS_BETWEEN_EMAIL_LOOKUPS = 0;

const inputItems = $input.all();
const results = [];

function clean(value) {
  return String(value || '').trim();
}

function cleanLower(value) {
  return String(value || '').toLowerCase().trim();
}

function getEmail(json) {
  return cleanLower(json['Email'] || json[' Email']);
}

function getAlias(json) {
  return clean(json['Alias'] || json.alias || json[' Agent Alias'] || json['Agent Alias'] || '');
}

function isUsefulSearchTerm(value) {
  return value && value.length >= 3;
}

function isBlankAgentRow(agentName, email, alias) {
  return !agentName && !email && !alias;
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function slackGet(url) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: {
        Authorization: `Bearer ${SLACK_TOKEN}`,
      },
      json: true,
    });

    return response;
  } catch (error) {
    return {
      ok: false,
      error: error.message || 'http_request_failed',
    };
  }
}

// Cache para no llamar users.list muchas veces.
// Solo lo usamos si hay que hacer fallback por nombre/alias.
let cachedSlackMembers = null;
let usersListError = null;

async function getAllSlackMembers() {
  if (cachedSlackMembers) return cachedSlackMembers;
  if (usersListError) return [];

  const members = [];
  let cursor = '';

  do {
    const url = `https://slack.com/api/users.list?limit=200${cursor ? `&cursor=${encodeURIComponent(cursor)}` : ''}`;

    const data = await slackGet.call(this, url);

    if (!data.ok) {
      usersListError = data.error || 'slack_api_error';
      return [];
    }

    for (const user of data.members || []) {
      if (user.deleted || user.is_bot) continue;
      members.push(user);
    }

    cursor = data.response_metadata?.next_cursor || '';
  } while (cursor);

  cachedSlackMembers = members;
  return cachedSlackMembers;
}

async function findByNameOrAlias(agentName, alias) {
  const searchTerms = [agentName, alias].filter(isUsefulSearchTerm);

  if (searchTerms.length === 0) {
    return null;
  }

  const members = await getAllSlackMembers.call(this);

  for (const user of members) {
    const displayName = cleanLower(user.profile?.display_name);
    const realName = cleanLower(user.profile?.real_name);
    const userName = cleanLower(user.name);

    const candidates = [displayName, realName, userName].filter(Boolean);

    const found = searchTerms.some((term) =>
      candidates.some((candidate) =>
        candidate === term || candidate.includes(term)
      )
    );

    if (found) {
      return user;
    }
  }

  return null;
}

for (const item of inputItems) {
  const json = item.json || {};

  const email = getEmail(json);
  const agentNameOriginal = clean(json['Agent Name'] || json.agentName || json.Agent);
  const agentName = cleanLower(agentNameOriginal);
  const aliasOriginal = getAlias(json);
  const alias = cleanLower(aliasOriginal);

  // Ignorar filas completamente vacías.
  if (isBlankAgentRow(agentNameOriginal, email, aliasOriginal)) {
    continue;
  }

  // Saltar offboarded, conservando Alias para debug.
  if (email === 'offboarded') {
    results.push({
      json: {
        _skip: true,
        reason: 'offboarded',
        row_number: json.row_number,
        'Agent Name': agentNameOriginal,
        Alias: aliasOriginal,
        Email: email,
      },
    });
    continue;
  }

  // 1. Buscar primero por email.
  if (email) {
    const data = await slackGet.call(
      this,
      `https://slack.com/api/users.lookupByEmail?email=${encodeURIComponent(email)}`
    );

    if (data.ok && data.user && !data.user.deleted) {
      results.push({
        json: {
          row_number: json.row_number,
          'Agent Name': agentNameOriginal,
          Alias: aliasOriginal,
          'Slack ID': data.user.id,
          Email: data.user.profile?.email || email,
          match_method: 'email',
        },
      });

      if (DELAY_MS_BETWEEN_EMAIL_LOOKUPS > 0) {
        await sleep(DELAY_MS_BETWEEN_EMAIL_LOOKUPS);
      }

      continue;
    }

    // Errores críticos: conviene devolverlos claro.
    if (data.error === 'missing_scope') {
      results.push({
        json: {
          _skip: true,
          reason: 'missing_scope',
          needed: data.needed || 'users:read.email',
          provided: data.provided || '',
          row_number: json.row_number,
          'Agent Name': agentNameOriginal,
          Alias: aliasOriginal,
          Email: email,
        },
      });
      continue;
    }

    if (data.error === 'invalid_auth' || data.error === 'not_authed') {
      results.push({
        json: {
          _skip: true,
          reason: data.error,
          row_number: json.row_number,
          'Agent Name': agentNameOriginal,
          Alias: aliasOriginal,
          Email: email,
        },
      });
      continue;
    }

    // Si el email no existe en Slack, seguimos al fallback por nombre/alias.
  }

  // 2. Fallback por Agent Name o Alias usando users.list cacheado.
  const matched = await findByNameOrAlias.call(this, agentName, alias);

  if (matched) {
    results.push({
      json: {
        row_number: json.row_number,
        'Agent Name': agentNameOriginal,
        Alias: aliasOriginal,
        'Slack ID': matched.id,
        Email: matched.profile?.email || email || '',
        match_method: 'name_or_alias',
      },
    });
    continue;
  }

  // Si no encontró Slack ID, igual devolvemos Agent Name + Email + Alias.
  // Esto permite que Prepare Agent Data use el email y el alias aunque Slack no haya encontrado usuario.
  results.push({
    json: {
      _skip: true,
      reason: usersListError || 'no_match_found',
      row_number: json.row_number,
      'Agent Name': agentNameOriginal,
      Alias: aliasOriginal,
      Email: email,
    },
  });

  if (DELAY_MS_BETWEEN_EMAIL_LOOKUPS > 0) {
    await sleep(DELAY_MS_BETWEEN_EMAIL_LOOKUPS);
  }
}

return results;

