const items = $input.all();
const output = [];

function clean(value) {
  return String(value ?? '')
    .replace(/\s+/g, ' ')
    .trim();
}

function decodeHtml(value) {
  return clean(String(value ?? '')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&#8599;/g, '↗')
    .replace(/&#9679;/g, '●')
  );
}

function stripTags(value) {
  return clean(String(value ?? '').replace(/<[^>]*>/g, ''));
}

function extractFirst(text, regex) {
  const match = String(text || '').match(regex);
  return match ? match[1] : '';
}

function getDaysFromLastCommunication(value) {
  const text = clean(value);

  if (!text || /^today$/i.test(text)) {
    return 0;
  }

  const dayMatch = text.match(/(\d+)\s*day/i);
  if (dayMatch) {
    return Number(dayMatch[1]);
  }

  const numberMatch = text.match(/^(\d+)/);
  return numberMatch ? Number(numberMatch[1]) : 0;
}

for (const item of items) {
  const agentData = item.json || {};

  const html = String(agentData.leadsHTML || '');
  if (!html) continue;

  const reportDate = agentData.today || new Date().toISOString().slice(0, 10);

  const assignedAgent =
    agentData.agentName ||
    agentData.sourceLeadAgentName ||
    '';

  const matchedAgentName = agentData.matchedAgentName || '';
  const agentEmail = agentData.agentEmail || '';
  const slackUserId = agentData.slackUserId || '';
  const reportedUrgentCount = Number(agentData.urgentCount || 0);

  /*
    Cada lead card del HTML inicia con:
    <table ... style="margin-bottom:10px;"><tr><td bgcolor="..."

    Los urgentes tienen:
    border-left:4px solid #dc2626
  */
  const cards = html
    .split(/(?=<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:10px;"><tr><td bgcolor=")/g)
    .filter(card => card && card.trim());

  let urgentIndexForAgent = 0;

  for (const card of cards) {
    const isUrgent = card.includes('border-left:4px solid #dc2626');

    if (!isUrgent) continue;

    const fubUrl = decodeHtml(
      extractFirst(card, /<a href="([^"]+)"/)
    );

    const leadId =
      extractFirst(fubUrl, /\/people\/view\/(\d+)/) ||
      extractFirst(card, /\/people\/view\/(\d+)/);

    const leadName = decodeHtml(stripTags(
      extractFirst(
        card,
        /font-size:15px;font-weight:700;color:#1a1a2e;">([\s\S]*?)<\/td>/
      )
    ));

    const spans = [...card.matchAll(/<span\b[^>]*>([\s\S]*?)<\/span>/g)]
      .map(match => decodeHtml(stripTags(match[1])));

    const stage = spans[0] || '';
    const leadSource = spans[1] || '';

    const timeWithoutContact = decodeHtml(stripTags(
      extractFirst(card, /&#9679;\s*([\s\S]*?)<\/td>/)
    ));

    const daysWithoutContact = getDaysFromLastCommunication(timeWithoutContact);

    urgentIndexForAgent++;

    output.push({
      json: {
        reportDate,

        leadId,
        leadName,

        assignedAgent,
        matchedAgentName,
        agentEmail,
        slackUserId,

        timeWithoutContact,
        daysWithoutContact,

        stage,
        leadSource,
        fubUrl,

        isUrgent: true,
        urgentRule: 'Last Communication >= 7 days',
        extractionSource: 'Prepare Agent Data - Riverside > leadsHTML',

        agentUrgentIndex: urgentIndexForAgent,
        agentUrgentCountReported: reportedUrgentCount,

        snapshotKey: `${reportDate}_${leadId}`,
      },
    });
  }
}

return output;

const row = $json;

const processedAt = new Date().toISOString();
const office = 'Riverside';

function parseReportDate(value) {
  const parsed = new Date(value);

  if (!Number.isNaN(parsed.getTime())) {
    return parsed;
  }

  return new Date();
}

function formatDateISO(date) {
  return date.toISOString().slice(0, 10);
}

function getWeekKey(reportDateValue) {
  const date = parseReportDate(reportDateValue);

  // Semana lunes-domingo
  const day = date.getDay(); // Sunday = 0, Monday = 1
  const diffToMonday = day === 0 ? -6 : 1 - day;

  const weekStart = new Date(date);
  weekStart.setDate(date.getDate() + diffToMonday);

  const weekEnd = new Date(weekStart);
  weekEnd.setDate(weekStart.getDate() + 6);

  const weekStartISO = formatDateISO(weekStart);
  const weekEndISO = formatDateISO(weekEnd);

  return `${weekStartISO}_to_${weekEndISO}`;
}

const reportDate = row.reportDate || '';
const weekKey = getWeekKey(reportDate);

return {
  json: {
    office,

    reportDate,
    weekKey,

    leadId: row.leadId || '',
    leadName: row.leadName || '',

    assignedAgent: row.assignedAgent || '',
    matchedAgentName: row.matchedAgentName || '',
    agentEmail: row.agentEmail || '',
    slackUserId: row.slackUserId || '',

    timeWithoutContact: row.timeWithoutContact || '',
    daysWithoutContact: Number(row.daysWithoutContact || 0),

    stage: row.stage || '',
    leadSource: row.leadSource || '',
    fubUrl: row.fubUrl || '',

    isUrgent: row.isUrgent === true,
    urgentRule: row.urgentRule || 'Last Communication >= 7 days',

