    processedAt,
  },
};

// ── DRY RUN CONFIG (set to false for production) ──────────
const DRY_RUN = false;
const DRY_RUN_EMAIL = 'manager@example.com';
const DRY_RUN_SLACK_ID = 'UXXXXXXXXXX';
// ────────────────────────────────────────────────────────────

const STAGE_COLORS = {
  'Active Listing':      { bg: '#eff6ff', color: '#1d4ed8' },
  'Appointment Set':     { bg: '#fce7f3', color: '#9d174d' },
  'Attempted Contact':   { bg: '#fee2e2', color: '#991b1b' },
  'Met with customer':   { bg: '#dbeafe', color: '#1e40af' },
  'Nurture':             { bg: '#f3f4f6', color: '#4b5563' },
  'Showing Homes':       { bg: '#fef3c7', color: '#92400e' },
  'Spoke with Customer': { bg: '#ede9fe', color: '#5b21b6' },
  'Submitting Offers':   { bg: '#ecfdf5', color: '#065f46' },
  'Under Contract':      { bg: '#d1fae5', color: '#065f46' },
};

const PIPELINE_COLORS = ['#3b82f6','#8b5cf6','#f59e0b','#10b981','#1e40af','#6366f1','#f97316'];

function norm(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ');
}

function clean(value) {
  return String(value || '').trim();
}

function getDays(lastComm) {
  return parseInt((lastComm || '0').split(' ')[0]) || 0;
}

function getInitials(name) {
  const p = clean(name).split(' ').filter(Boolean);
  if (!p.length) return '';
  return p.length >= 2
    ? (p[0][0] + p[p.length - 1][0]).toUpperCase()
    : p[0].substring(0, 2).toUpperCase();
}

function dotColor(days) {
  return days >= 7 ? '#dc2626' : days >= 4 ? '#f59e0b' : '#10b981';
}

function textColor(days) {
  return days >= 7 ? '#dc2626' : days >= 4 ? '#f59e0b' : '#10b981';
}

function borderColor(days) {
  return days >= 7 ? '#dc2626' : days >= 4 ? '#f59e0b' : '#10b981';
}

function todayLabel() {
  return new Date().toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

const inputItems = $input.all();

// ── 1. Separate dynamic agent directory from lead rows ──────
const agentRows = [];
const leadRows = [];

for (const item of inputItems) {
  const row = item.json || {};

  const agentName = clean(row['Agent Name']);
  const email = clean(row.Email || row[' Email']);
  const slackId = clean(row['Slack ID'] || row.SlackID || row.slackUserId);
  const alias = clean(row.Alias);

  const isAgentDirectoryRow =
    !!agentName || !!email || !!slackId || Object.prototype.hasOwnProperty.call(row, 'Agent Name');

  const isLeadRow =
    !!clean(row.Agent) &&
    !!clean(row.ID) &&
    !!clean(row.Name);

  if (isLeadRow) {
    leadRows.push(row);
    continue;
  }

  if (isAgentDirectoryRow) {
    // Keep offboarded/skipped rows out of the usable directory.
    if (row._skip || norm(email) === 'offboarded') continue;

    if (!agentName) continue;

    agentRows.push({
      row_number: row.row_number,
      agentName,
      alias,
      email,
      slackId,
      match_method: row.match_method || '',
    });
  }
}

// ── 2. Build lookup maps by Agent Name and Alias ────────────
const agentsByName = {};
const agentsByAlias = {};

for (const agent of agentRows) {
  const nameKey = norm(agent.agentName);
  const aliasKey = norm(agent.alias);

  if (nameKey && !agentsByName[nameKey]) {
    agentsByName[nameKey] = agent;
  }

  if (aliasKey && !agentsByAlias[aliasKey]) {
    agentsByAlias[aliasKey] = agent;
  }
}

function findAgentForLeadAgent(leadAgentName) {
  const key = norm(leadAgentName);

  if (agentsByName[key]) {
    return {
      agent: agentsByName[key],
      source: 'name',
    };
  }

  if (agentsByAlias[key]) {
    return {
      agent: agentsByAlias[key],
      source: 'alias',
    };
  }

  return {
    agent: null,
    source: 'none',
  };
}

// ── 3. Group leads by their FUB Agent field ─────────────────
const agentLeads = {};

for (const row of leadRows) {
  const agent = clean(row.Agent);
  if (!agent || agent === 'Agent') continue;

  if (!agentLeads[agent]) agentLeads[agent] = [];
  agentLeads[agent].push(row);
}

// ── 4. Generate one dashboard per FUB agent with leads ──────
const results = [];
const skipped = [];
const today = todayLabel();

for (const [leadAgentName, leads] of Object.entries(agentLeads)) {
  const match = findAgentForLeadAgent(leadAgentName);
  const matchedAgent = match.agent;

  if (!matchedAgent) {
    skipped.push({
      leadAgentName,
      totalLeads: leads.length,
      reason: 'agent_not_found_in_directory',
    });
    continue;
  }

  const agentName = leadAgentName;
  const matchedAgentName = matchedAgent.agentName;
  const matchedAlias = matchedAgent.alias || '';
  const agentMatchSource = match.source;
  const email = matchedAgent.email || '';
  const slackUserId = matchedAgent.slackId || '';

  if (!email && !slackUserId) {
    skipped.push({
      leadAgentName,
      matchedAgentName,
      matchedAlias,
      totalLeads: leads.length,
      reason: 'matched_agent_missing_email_and_slack_id',
    });
    continue;
  }

  const urgent = leads.filter(l => getDays(l['Last Communication']) >= 7);
  const onTrack = leads.length - urgent.length;
  const initials = getInitials(matchedAgentName || agentName);
  const sortedLeads = [...leads].sort(
    (a, b) => getDays(b['Last Communication']) - getDays(a['Last Communication'])
  );

  const pipeline = {};
  for (const l of leads) {
    const s = l.Stage || 'Unknown';
    pipeline[s] = (pipeline[s] || 0) + 1;
  }

  // ── LEAD CARDS (table-based, Gmail-safe) ─────────────────
  let leadsHTML = '';

  for (const lead of sortedLeads) {
    const days = getDays(lead['Last Communication']);
    const sc = STAGE_COLORS[lead.Stage] || { bg: '#f3f4f6', color: '#4b5563' };
    const timeLabel = days === 0 ? 'Today' : lead['Last Communication'] || '';
    const cardBg = days >= 7 ? '#fffbfb' : '#ffffff';
    const source = clean(lead['Lead Source']).replace('Zillow Preferred', 'ZP');

    leadsHTML += `<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:10px;"><tr><td bgcolor="${cardBg}" style="border-radius:14px;border-left:4px solid ${borderColor(days)};padding:16px;"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:10px;"><tr><td style="font-size:15px;font-weight:700;color:#1a1a2e;">${lead.Name || ''}</td><td align="right"><a href="${lead.Link || '#'}" onclick="window.open(this.href,'_blank','noopener,noreferrer');return false;" target="_blank" rel="noopener noreferrer" style="background:#1a1a2e;color:#fff;text-decoration:none;font-size:11px;font-weight:600;padding:5px 12px;border-radius:20px;display:inline-block;">FUB &#8599;</a></td></tr></table><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="white-space:nowrap;padding-right:6px;"><span style="font-size:11px;font-weight:600;padding:3px 10px;border-radius:20px;text-transform:uppercase;letter-spacing:.5px;background:${sc.bg};color:${sc.color}">${lead.Stage || ''}</span></td><td style="white-space:nowrap;padding-right:6px;"><span style="font-size:10px;font-weight:600;padding:2px 8px;border-radius:20px;background:#f0f2f5;color:#6b7280;text-transform:uppercase;">${source}</span></td><td align="right" style="font-size:12px;font-weight:600;color:${textColor(days)};white-space:nowrap;">&#9679; ${timeLabel}</td></tr></table></td></tr></table>`;
  }

  // ── PIPELINE BARS (table-based) ───────────────────────────
  let pipelineHTML = '';
  const maxCount = Math.max(...Object.values(pipeline), 1);
  let ci = 0;

  for (const [stage, count] of Object.entries(pipeline).sort((a, b) => b[1] - a[1])) {
    const pct = Math.round((count / maxCount) * 100);
    const barColor = PIPELINE_COLORS[ci % PIPELINE_COLORS.length];

    pipelineHTML += `<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:10px;"><tr><td width="140" style="font-size:12px;font-weight:600;color:#374151;padding-right:10px;">${stage}</td><td bgcolor="#f0f2f5" style="border-radius:4px;"><table height="8" cellpadding="0" cellspacing="0" border="0" style="width:${pct}%;"><tr><td bgcolor="${barColor}" style="border-radius:4px;height:8px;"></td></tr></table></td><td width="22" align="right" style="font-size:12px;font-weight:700;color:#1a1a2e;padding-left:8px;">${count}</td></tr></table>`;

    ci++;
  }

  // ── URGENT BANNER (table-based) ───────────────────────────
  const urgentBanner = urgent.length > 0
    ? `<table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td bgcolor="#fef2f2" style="border-radius:12px;border:1px solid #fca5a5;border-left:4px solid #dc2626;padding:14px 16px;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="32" style="font-size:20px;vertical-align:top;padding-right:10px;">&#128680;</td><td style="vertical-align:top;"><div style="font-size:13px;font-weight:700;color:#b91c1c;">Action Required</div><div style="font-size:12px;color:#ef4444;margin-top:4px;line-height:1.5;">${urgent.length} lead${urgent.length > 1 ? 's' : ''} without contact for 7+ days. Add a note &amp; task in FUB to avoid reassignment.</div></td></tr></table></td></tr></table>`
    : `<table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td bgcolor="#f0fdf4" style="border-radius:12px;border:1px solid #86efac;border-left:4px solid #10b981;padding:14px 16px;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="32" style="font-size:20px;padding-right:10px;">&#9989;</td><td style="font-size:13px;font-weight:600;color:#065f46;">Great job! All leads are within 7 days of contact.</td></tr></table></td></tr></table>`;

  const slackUrgentLeads = urgent.slice(0, 5).map(l => ({
    name: l.Name,
    stage: l.Stage,
    lastComm: l['Last Communication'],
    link: l.Link || 'https://yourcompany.followupboss.com',
    id: String(l.ID || Math.random()).replace('.', ''),
  }));

  results.push({
    json: {
      agentName,
      matchedAgentName,
      matchedAlias,
      agentMatchSource,
      agentEmail: email,
      initials,
      totalLeads: leads.length,
      urgentCount: urgent.length,
      onTrack,
      leadsHTML,
      pipelineHTML,
      urgentBanner,
      slackUrgentLeads,
      slackUserId,
      subject: `Your Zillow Dashboard - Week of ${today}`,
      today,

      // Debug fields. You can remove these after validation.
      sourceLeadAgentName: leadAgentName,
      matchedDirectoryRow: matchedAgent.row_number || null,
    },
  });
}

// Optional debug item only if nothing matched.
if (!results.length) {
  return [{
    json: {
      _debug: true,
      reason: 'no_dashboards_generated',
      inputItems: inputItems.length,
      agentRows: agentRows.length,
      leadRows: leadRows.length,
      groupedLeadAgents: Object.keys(agentLeads),
      skipped,
    },
  }];
}

if (DRY_RUN) {
  const first = results[0];
  return [{
    json: {
      ...first.json,
      agentEmail: DRY_RUN_EMAIL,
      slackUserId: DRY_RUN_SLACK_ID,
      dryRunOriginalEmail: first.json.agentEmail,
      dryRunOriginalSlackUserId: first.json.slackUserId,
    },
  }];
}

return results;
